import pandas as pd
import numpy as np
import argparse
import os
import joblib
import logging
import json
from sklearn.metrics import mean_squared_error, mean_absolute_error, r2_score
import matplotlib.pyplot as plt

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--reports-dir", default="reports/figures", help="Directory with reports")
    args = parser.parse_args()
    
    # Path to metrics file generated by week6_ensemble_model.py
    metrics_path = os.path.join(args.reports_dir, "ensemble_metrics.txt")
    
    report_content = "# Final Model Evaluation Report\n\n"
    
    if os.path.exists(metrics_path):
        logging.info(f"Reading metrics from {metrics_path}")
        with open(metrics_path, "r") as f:
            metrics_data = f.read()
            
        report_content += "## Performance Metrics (RMSE)\n"
        report_content += metrics_data
        report_content += "\n\n"
        report_content += "## artifacts\n"
        report_content += "- Loss Curves: `reports/figures/lstm_loss_curve.png`\n"
        report_content += "- Prediction Plots: `reports/figures/lstm_predictions.png`\n"
        report_content += "- Ensemble Comparison: `reports/figures/ensemble_comparison.png`\n"
    else:
        logging.warning(f"Metrics file not found at {metrics_path}. Run week6_ensemble_model.py first.")
        report_content += "## Error\nMetrics file not found. Please run the ensemble model script first.\n"

    # Save final report
    final_report_path = os.path.join("reports", "final_project_report.md")
    with open(final_report_path, "w") as f:
        f.write(report_content)
        
    logging.info(f"Final report saved to {final_report_path}")
    print(report_content)

if __name__ == "__main__":
    main()
